const countries = ($json.countries || []).map(c => String(c));
const officialHousingSources = {
 'United States': ['https://housing.mit.edu/','https://housing.stanford.edu/'],
 'United Kingdom': ['https://www.ox.ac.uk/admissions/graduate/accommodation','https://www.ucl.ac.uk/accommodation/'],
 'Canada': ['https://www.utoronto.ca/campus-life/housing','https://you.ubc.ca/finances/housing/'],
 'Australia': ['https://www.sydney.edu.au/study/accommodation.html','https://students.unimelb.edu.au/student-support/accommodation'],
 'Germany': ['https://www.daad.de/en/study-and-research-in-germany/plan-your-studies/accommodation/'],
 'France': ['https://www.campusfrance.org/en/student-housing-in-france'],
 'Netherlands': ['https://www.studyinnl.org/plan-your-stay/accommodation'],
 'Ireland': ['https://www.ucd.ie/residences/','https://www.tcd.ie/accommodation/'],
 'New Zealand': ['https://www.auckland.ac.nz/en/study/accommodation.html'],
 'Singapore': ['https://nus.edu.sg/osa/student-services/hostel-admission'],
 'Japan': ['https://www.u-tokyo.ac.jp/en/prospective-students/housing.html'],
 'Sweden': ['https://studyinsweden.se/moving-to-sweden/finding-accommodation/'],
 'Norway': ['https://www.sio.no/en/housing'],
 'Denmark': ['https://studyindenmark.dk/live-in-denmark/housing'],
 'Finland': ['https://www.studyinfinland.fi/life-finland/student-housing'],
 'UAE': ['https://www.ku.ac.ae/student-life/housing']
};
const out = [];
for (const country of countries){
  const urls = officialHousingSources[country] || [];
  for (const url of urls){ out.push({json:{country, url, sourceType:'official_housing'}}); }
}
return out;

const src = $item(0).$node['Split In Batches'].json;
const statusCode = Number($json.statusCode || 0);
const ok = statusCode >= 200 && statusCode < 500;
return [{json:{country: src.country, url: src.url, sourceType: src.sourceType, statusCode, ok}}];
